import { IMessageComposer } from '@nitrots/nitro-renderer';

export class CreateGangRoleComposer implements IMessageComposer<any[]> {
    private _data: any[];

    constructor(
        name: string,
        bankAccess: boolean,
        kickMembers: boolean,
        inviteMembers: boolean,
        administrator: boolean
    ) {
        this._data = [
            name,
            bankAccess,
            kickMembers,
            inviteMembers,
            administrator,
        ];
    }

    public getMessageArray(): any[] {
         console.log('Sending CreateGangRoleComposer with data: ', this._data);
        return this._data;
       
    }

    public dispose(): void {}
}
